﻿// 20F - Normalize RSS Items (V2)
function toIsoDate(v) {
  if (!v) return 'unknown';
  const d = new Date(v);
  return isNaN(d.getTime()) ? 'unknown' : d.toISOString();
}

function stripHtml(s) {
  if (!s) return '';
  return String(s).replace(/<[^>]*>/g, ' ').replace(/\s+/g, ' ').trim();
}

function safeUrl(u) {
  if (!u || typeof u !== 'string') return 'unknown';
  return u.trim();
}

function inferSource(u) {
  try {
    const h = new URL(u).hostname.toLowerCase();
    if (h.includes('amf-france')) return 'AMF France';
    if (h.includes('boursorama')) return 'Boursorama';
    if (h.includes('investir') || h.includes('lesechos')) return 'Investir/Les Echos';
    if (h.includes('reuters')) return 'Reuters';
    if (h.includes('bloomberg')) return 'Bloomberg';
    if (h.includes('zonebourse')) return 'Zonebourse';
    if (h.includes('tradingview')) return 'TradingView';
    if (h.includes('euronext')) return 'Euronext';
    return h.replace(/^www\./, '');
  } catch {
    return 'unknown';
  }
}

let feedCtx = {};
try {
  feedCtx = $('20D - Split Feeds').item.json || {};
} catch {
  feedCtx = {};
}

const fetchedAt = new Date().toISOString();
const rows = $input.all().map(i => i.json || {});

return rows.map(r => {
  const canonicalUrl = safeUrl(r.link || r.url || r.guid);
  const title = (typeof r.title === 'string' && r.title.trim()) ? stripHtml(r.title) : 'unknown';
  const snippet = stripHtml(r.contentSnippet || r.content || r.summary || '');
  const publishedAt = toIsoDate(r.isoDate || r.pubDate || r.published || r.date || r.updated || fetchedAt);

  return {
    json: {
      run_id: feedCtx.run_id || '',
      fetchedAt,
      publishedAt,
      source: inferSource(canonicalUrl),
      url: canonicalUrl,
      canonicalUrl,
      title,
      snippet,
      symbols: [],
      type: 'macro',
      feedUrl: feedCtx.url || '',
      sourceTier: feedCtx.sourceTier || 2,
      sourceId: feedCtx.sourceId || '',
      _itemsLoopReset: true,
    }
  };
});

// 20G0 — Add deterministic dedupeKey + eventKey (V2)
const crypto = require('crypto');

const LOOKBACK_DAYS = 120;

function hash(s) {
  return crypto.createHash('sha256').update(String(s)).digest('hex');
}

function normalizeTitle(s) {
  return String(s || '')
    .toLowerCase()
    .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
    .replace(/<[^>]*>/g, ' ')
    .replace(/[^a-z0-9\s]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function normalizeUrl(u) {
  if (!u || typeof u !== 'string') return '';
  try {
    const url = new URL(u);
    const drop = ['utm_', 'fbclid', 'gclid', 'ref', 'src'];
    const remove = [];
    url.searchParams.forEach((_, k) => {
      if (drop.some(p => k.toLowerCase().startsWith(p))) remove.push(k);
    });
    remove.forEach(k => url.searchParams.delete(k));
    return url.toString().replace(/\/$/, '');
  } catch {
    return String(u).trim();
  }
}

function toIso(v) {
  if (!v || v === 'unknown') return 'unknown';
  const d = new Date(v);
  return isNaN(d.getTime()) ? 'unknown' : d.toISOString();
}

return $input.all().map((item) => {
  const n = { ...(item.json || {}) };

  const cleanUrl = normalizeUrl(n.canonicalUrl || n.url || n.link || '');
  const cleanDate = toIso(n.publishedAt || n.fetchedAt);
  const dayBucket = cleanDate !== 'unknown' ? cleanDate.slice(0, 10) : 'unknown-day';
  const titleNorm = normalizeTitle(n.title || '');

  const dedupeSignature = cleanUrl
    ? `URL|${cleanUrl}`
    : `TXT|${titleNorm}|${String(n.source || 'unknown').toLowerCase()}|${dayBucket}`;

  // Event key: same story clustering across many URLs in same day
  const eventSignature = `${titleNorm.slice(0, 180)}|${dayBucket}`;

  n.canonicalUrlNormalized = cleanUrl;
  n.publishedAtNormalized = cleanDate;
  n.dedupeKey = hash(dedupeSignature);
  n.eventKey = hash(eventSignature);

  const cutoff = new Date();
  cutoff.setDate(cutoff.getDate() - LOOKBACK_DAYS);
  const dt = cleanDate === 'unknown' ? null : new Date(cleanDate);
  const tooOld = !dt || isNaN(dt.getTime()) ? false : dt < cutoff;

  n._isValid = !!titleNorm && !tooOld;
  n._kind = 'news_item';
  n._itemsLoopReset = false;

  return { json: n, pairedItem: item.pairedItem };
});

// 20F1 - Attach sector dictionary + detect sector hints (V2)
function normalizeText(s) {
  return String(s || '')
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/[^a-z0-9\s]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function unique(arr) {
  return Array.from(new Set((arr || []).filter(Boolean)));
}

function safeParseArray(v) {
  if (Array.isArray(v)) return v;
  if (typeof v === 'string') {
    try {
      const parsed = JSON.parse(v);
      return Array.isArray(parsed) ? parsed : [];
    } catch {
      return [];
    }
  }
  return [];
}

let sectorDictionary = [];
try {
  const raw = $items('20A2 - Build Sector Dictionary')[0]?.json?.sectorDictionary;
  sectorDictionary = safeParseArray(raw).map((x) => String(x || '').trim()).filter(Boolean);
} catch {
  sectorDictionary = [];
}

const sectorMatchers = sectorDictionary.map((sector) => ({
  label: sector,
  norm: normalizeText(sector),
})).filter((x) => x.norm.length >= 3);

return $input.all().map((item) => {
  const j = item.json || {};
  const textNorm = normalizeText(`${j.title || ''} ${j.snippet || ''}`);

  const candidateSectors = [];
  for (const m of sectorMatchers) {
    if (textNorm.includes(m.norm)) candidateSectors.push(m.label);
  }

  return {
    json: {
      ...j,
      symbols: [],
      type: 'macro',
      universeSectors: sectorDictionary,
      candidateSectors: unique(candidateSectors).slice(0, 5),
    },
    pairedItem: item.pairedItem,
  };
});

// 20G1C - Pre-score heuristic impact (V2)
const HIGH = [
  'inflation', 'cpi', 'ppi', 'ecb', 'fed', 'taux', 'rate', 'yield',
  'recession', 'gdp', 'pmi', 'chomage', 'unemployment', 'war', 'tariff',
  'oil', 'opec', 'sanction', 'guidance', 'profit warning', 'default',
  'downgrade', 'bankruptcy', 'acquisition', 'merger', 'earnings'
];

const MID = ['forecast', 'outlook', 'results', 'macro', 'sector', 'dividend', 'buyback'];

function scoreText(text) {
  const t = String(text || '').toLowerCase();
  let s = 0;
  for (const k of HIGH) if (t.includes(k)) s += 2;
  for (const k of MID) if (t.includes(k)) s += 1;
  return s;
}

return $input.all().map((i) => {
  const j = i.json || {};
  const text = `${j.title || ''} ${j.snippet || ''}`;
  const kw = scoreText(text);
  const hasSectorHint = Array.isArray(j.candidateSectors) && j.candidateSectors.length > 0;

  let score = Math.min(10, kw + (hasSectorHint ? 2 : 1));
  score += Number(j.sourceTier === 1 ? 2 : (j.sourceTier === 2 ? 1 : 0));
  score = Math.min(10, score);

  const urgency = score >= 8 ? 'immediate' : score >= 6 ? 'today' : score >= 4 ? 'this_week' : 'low';

  return {
    json: {
      ...j,
      preImpactScore: score,
      preUrgency: urgency,
      preAnalyzeHint: score >= 4,
    },
    pairedItem: i.pairedItem,
  };
});

// 20G2 — Route new vs seen + stale re-analysis + event clustering (V2)
function toNum(x, def = 0) {
  const n = Number(x);
  return Number.isFinite(n) ? n : def;
}

function hoursBetween(a, b) {
  const da = new Date(a), db = new Date(b);
  if (isNaN(da.getTime()) || isNaN(db.getTime())) return 9999;
  return Math.abs((da.getTime() - db.getTime()) / 3600000);
}

const n = $json || {};
const nowIso = new Date().toISOString();

let historyIndex = {};
let historyEventIndex = {};
try {
  const idxNode = $items('20G1B - Build History Index')[0]?.json || {};
  historyIndex = idxNode.historyIndex || {};
  historyEventIndex = idxNode.historyEventIndex || {};
} catch {
  historyIndex = {};
  historyEventIndex = {};
}

const dKey = n.dedupeKey;
const eKey = n.eventKey;
const old = (dKey && historyIndex[dKey]) ? historyIndex[dKey] : null;
const oldEvent = (!old && eKey && historyEventIndex[eKey]) ? historyEventIndex[eKey] : null;

const REANALYZE_HOURS = 12;

if (old) {
  const age = hoursBetween(nowIso, old.firstSeenAt || old.publishedAt || old.analyzedAt || nowIso);
  const preImpact = toNum(n.preImpactScore, 0);

  if (preImpact >= 7 && age >= REANALYZE_HOURS) {
    return [{ json: { ...n, _action: 'analyze', _reason: 'stale_high_impact_refresh', seenNowAt: nowIso } }];
  }

  return [{
    json: {
      ...n,
      _action: 'skip',
      _reason: 'duplicate_known',
      seenNowAt: nowIso,
      historyRowNumber: old.row_number ?? old.rowNumber ?? old.row ?? null,

      // restore previously analyzed strategic fields
      ImpactScore: old.ImpactScore ?? old.impactScore ?? 0,
      confidence: old.confidence ?? 0,
      urgency: old.urgency ?? 'low',
      notes: old.notes ?? '',
      Snippet: old.Snippet ?? old.snippet ?? n.snippet ?? '',
      symbols: old.symbols ?? (Array.isArray(n.symbols) ? n.symbols.join(', ') : ''),
      type: old.type ?? n.type ?? 'macro',
      Regime: old.Regime ?? old.market_regime ?? 'Neutral',
      Theme: old.Theme ?? old.macro_theme ?? 'Résultats/Micro',
      Winners: old.Winners ?? old.sectors_bullish ?? '',
      Losers: old.Losers ?? old.sectors_bearish ?? '',
      Strategy: old.Strategy ?? old.strategic_summary ?? '',
      firstSeenAt: old.firstSeenAt ?? old.analyzedAt ?? old.publishedAt ?? n.publishedAt,
      analyzedAt: old.analyzedAt ?? old.firstSeenAt ?? nowIso,
    }
  }];
}

if (oldEvent && !n.preAnalyzeHint) {
  return [{
    json: {
      ...n,
      _action: 'skip',
      _reason: 'event_cluster_duplicate',
      seenNowAt: nowIso,
      ImpactScore: oldEvent.ImpactScore ?? oldEvent.impactScore ?? 0,
      confidence: oldEvent.confidence ?? 0,
      urgency: oldEvent.urgency ?? 'low',
      notes: `Cluster duplicate of prior eventKey ${eKey}`,
      Snippet: n.snippet || oldEvent.Snippet || '',
      symbols: Array.isArray(n.symbols) ? n.symbols.join(', ') : (n.symbols || ''),
      type: n.type || oldEvent.type || 'macro',
      Regime: oldEvent.Regime ?? 'Neutral',
      Theme: oldEvent.Theme ?? 'Résultats/Micro',
      Winners: oldEvent.Winners ?? '',
      Losers: oldEvent.Losers ?? '',
      Strategy: oldEvent.Strategy ?? '',
      firstSeenAt: oldEvent.firstSeenAt ?? oldEvent.analyzedAt ?? nowIso,
      analyzedAt: oldEvent.analyzedAt ?? nowIso,
    }
  }];
}

return [{
  json: {
    ...n,
    _action: 'analyze',
    _reason: 'new_or_material',
    seenNowAt: nowIso,
  }
}];

// 20H0 - Prepare LLM input (V2)
function stripHtml(s) {
  if (!s) return '';
  return String(s).replace(/<[^>]*>/g, ' ').replace(/\s+/g, ' ').trim();
}

function toIso(x) {
  if (!x || x === 'unknown') return 'unknown';
